  let rfcDeriver = acquire Deriver(key);   // new Rfc2898DeriveBytes(key, salt, 10000, SHA256)
  // derive Key + IV via rfcDeriver.GetBytes(...)
  // no `release rfcDeriver;` — the deriver is never disposed (OWN001)
}

