module BadScratchEscape

// OWN015: a scratch buffer may be stack-backed, so returning it would hand back
// a span into a frame that is about to pop. If you need to return a buffer, use
// Buffer.pooled(...) — a movable owned resource whose Return the checker enforces.

fn leak(size: int) -> Buffer {
    let tmp = Buffer.scratch(size, inline = 1024);
    return tmp;
}

module ScratchDemo

// A scratch buffer: prefer the stack, fall back to ArrayPool when the request
// exceeds the inline limit. The user states the intent; the checker proves it
// stays local; codegen emits both branches; and OwnTrace/OwnCounters log which
// backend was actually chosen at runtime.
//
//   python -m ownlang check  buffer_scratch.own   # ownership is clean
//   python -m ownlang emit   buffer_scratch.own   # stack-first + pool fallback
//   python -m ownlang report buffer_scratch.own   # what the compiler decided

policy DefaultScratch {
    inline_bytes     = 1024;
    fallback         = pool;
    trace            = debug;
    counters         = true;
    clear_on_release = false;
}

extern fn Fill(borrow_mut Buffer);
extern fn Hash(borrow Buffer);

fn parse(size: int) {
    let tmp = Buffer.scratch(size, inline = 1024, fallback = pool);
    borrow_mut tmp as bytes {
        Fill(bytes);
    }
    borrow tmp as view {
        Hash(view);
    }
    release tmp;
}

module StackDemo

// Strict stack mode: stackalloc only, the heap fallback is FORBIDDEN, the buffer
// cannot escape. A constant bound lowers to `stackalloc byte[N]`; a dynamic size
// requires a `max =` guard so the real stack frame is bounded — "we put up a
// fence", not "the user promised".

extern fn Fill(borrow_mut Buffer);

fn fixed_buf() {
    let line = Buffer.stack(256);           // -> Span<byte> line = stackalloc byte[256];
    borrow_mut line as m {
        Fill(m);
    }
    release line;
}

fn bounded(size: int)
{
    // dynamic size, but bounded: codegen emits a guard then slices the backing.
    let buf = Buffer.stack(size, max = 1024);
    borrow_mut buf as m {
        Fill(m);
    }
    release buf;
}

// Clean: acquire, look at it mutably then read-only, hand it back.
// Lowers to ArrayPool Rent/Return inside a try/finally (exception-safe).
module Gallery
resource Buffer {
  acquire rent
  release give
  emit_type    "byte[]"
  emit_acquire "ArrayPool<byte>.Shared.Rent({args})"
  emit_release "ArrayPool<byte>.Shared.Return({0})"
  emit_borrow  "{0}.AsSpan()"
}
extern fn Fill(borrow_mut Buffer);
extern fn Hash(borrow Buffer);
fn process(size: int) {
  let buf = acquire Buffer(size);
  borrow_mut buf as bytes { Fill(bytes); }
  borrow buf as view { Hash(view); }
  release buf;
}

