module PoolDemo

resource Buffer {
  acquire rent
  release give
}

// Canonical happy path: rent a buffer, look at it mutably then read it,
// hand it back. Checker proves it is returned on the single path; codegen
// hoists the release into a finally for exception-safety.
fn process(size: int) {
  let buf = acquire Buffer(size);

  borrow_mut buf as bytes {
    use bytes;
  }

  borrow buf as bytes {
    use bytes;
  }

  release buf;
}

module M
resource Conn { acquire open release close }
resource Token { acquire mint release burn kind "subscription token" }
extern fn Fill(borrow_mut Conn);
extern fn Hash(borrow Conn);
extern fn Store(consume Conn);
fn f(n: int) {
    let c = acquire Conn(1);
    if (n) {
        borrow c as r { use r; }
    }
    let d = move c;
    Store(d);
    return;
}
fn g(n: int) {
    let b = Buffer.scratch(n);
    release b;
}

