module M
policy Fast {
  inline_bytes = 256;
  clear_on_release = true;
  fallback = pool;
  trace = debug;
  counters = true;
}
fn f(n: int) {
  let a = Buffer.scratch(64, policy = Fast, clear = true);
  let b = Buffer.stack(size, max = 1024);
  let c = Buffer.inline(32);
  let d = Buffer.pooled(n);
  let e = Buffer.native(n);
  release a; release b; release c; release d; release e;
}

module M
