resource Other { acquire open release close }
fn ret_owned() -> Conn { let c = acquire Conn(1); return c; }
fn ret_borrow(x: &Conn) -> Conn { return x; }
fn ret_plain() -> Conn { let n = 3; return n; }
fn ret_wrong() -> Conn { let o = acquire Other(1); return o; }
fn ret_void_val() { let c = acquire Conn(1); return c; }
fn ret_missing() -> Conn { }

